INSERT INTO public.ci_monitor_alerts VALUES ('a1f94e81-fd82-4e34-a6ef-92ebc36f8dfe', 'Basenor / Electrek', 'https://www.basenor.com/blogs/news/tesla-optimus-pilot-production-line-gets-first-look-on-video', 'Tesla Optimus pilot production line first video revealed; Fremont conversion for 1M/year capacity underway', 'A video surfacing May 21, 2026 offers the clearest look yet at Tesla''s Optimus Gen 3 pilot production line at Fremont. Pilot production began Jan 21, 2026. Former Model S/X area being converted into a first-generation line designed for 1 million robots/year capacity, with mass production targeted late July/August 2026.', '239599f4-9419-4251-957f-a58532aa3980', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('761c5c0f-52cd-4d42-ac76-9414a89c0b3e', 'The Robot Report / Teslarati', 'https://www.therobotreport.com/from-evs-to-robotics-tesla-targets-10m-optimus-units-with-new-texas-plant/', 'Tesla Giga Texas North Campus: 5.2M sq ft Optimus factory targeting 10M robots/year, $5–10B investment', 'Permit documents reveal Tesla seeking to add 5.2 million sq ft at Giga Texas North Campus for a second-generation Optimus production line targeting 10 million robots per year (27,000/day). Estimated construction investment $5–10 billion. Site preparation underway, production expected summer 2027.', '239599f4-9419-4251-957f-a58532aa3980', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('eb6f761c-f838-4e58-8f3c-3ccb5172a2ec', 'BotInfo / Electrek', 'https://botinfo.ai/articles/tesla-optimus', 'Tesla Optimus Gen 3 hand upgrade: 22-DOF hands with 50 actuators across both forearms, body retains Gen 2 frame', 'Gen 3 label refers to an upgraded hand system, not an entirely new chassis. Robot retains Gen 2 body (173 cm, 57 kg) but gains significantly more capable hands with 22 degrees of freedom and 50 actuators across both forearms and hands. Musk warned initial production output will be "quite slow" with 10,000 unique parts.', '239599f4-9419-4251-957f-a58532aa3980', '1ef67e56-4d68-4287-bb82-1ac74bbdda14', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('ebea44e8-40f1-4ca5-9a58-be5838fd1f37', 'Automate.org / Engadget', 'https://www.automate.org/robotics/industry-insights/boston-dynamics-to-begin-production-on-redesigned-atlas-humanoid-in-2026', 'Boston Dynamics ships production-ready Atlas; all 2026 units committed to Hyundai RMAC and Google DeepMind', 'Boston Dynamics unveiled production-ready Atlas at CES January 2026 and began production at Boston HQ immediately. All 2026 deployments fully committed to Hyundai RMAC and Google DeepMind fleets. Hyundai Mobis supplies actuators with collaborative supply chain development.', 'e16ad5d5-78c2-4e49-88c6-c396385ef98d', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('f6d09df0-e152-4628-ba31-cdab834cffa0', 'New Atlas / Automate.org', 'https://newatlas.com/ai-humanoids/boston-dynamics-production-atlas-hyundai/', 'Hyundai $26B US investment includes 30,000-unit/year Atlas robot factory', 'Hyundai Motor Group announced $26 billion investment in US operations, including a new robotics factory capable of producing 30,000 Atlas robots per year. Plans to deploy tens of thousands of robots into Hyundai''s own manufacturing facilities. Factory completion targeted for 2028.', 'e16ad5d5-78c2-4e49-88c6-c396385ef98d', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('c153584a-c1d0-4b28-9ae1-400bfb33ee3b', 'Seoul Economic Daily / Medium / TechRadar', 'https://en.sedaily.com/international/2026/05/17/figure-ai-robot-sorts-100000-packages-in-81-hours-without', 'Figure 03 robots sort 101,391 packages in 81-hour autonomous marathon — planned 8hr demo ran 10x longer', 'Starting May 13, 2026, Figure AI livestreamed three Figure 03 robots in autonomous package sorting. Planned for 8 hours, the demo ran 81 hours with zero failures in the first 24 hours, sorting 101,391 packages (one every 3–4 seconds, 28,000+/day). Helix-02 AI ran entirely onboard with no teleoperation.', 'ce6cdf95-329c-450b-ab2c-fab3cb5eb52b', '35b986bf-1223-4bde-92ed-7ba4bcbfd385', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('a26507b4-c11f-42f5-9094-a73646c81035', 'The AI Insider / Interesting Engineering', 'https://theaiinsider.tech/2026/05/01/figure-ai-ramps-up-production-to-one-humanoid-robot-per-hour/', 'Figure AI production reaches 1 robot/hour at BotQ; 350+ Figure 03 units delivered, 80%+ first-pass yield', 'Figure ramped manufacturing from 1 robot/day to 1 robot/hour in under four months at BotQ facility. Over 350 Figure 03 units delivered. Dedicated assembly lines, custom manufacturing software across 150+ workstations, first-pass yields above 80%. Plans to ship 100,000 humanoids over four years.', 'ce6cdf95-329c-450b-ab2c-fab3cb5eb52b', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('0bfb55f6-2b04-484f-8270-42d1b47da1fa', 'Figure AI Official', 'https://www.figure.ai/news', 'Figure System 0 AI gains perception-conditioned whole-body control for stairs, ramps, and uneven terrain', 'Figure introduced perception-conditioned whole-body control in System 0 AI allowing Figure 03 to navigate stairs, ramps and uneven terrain using onboard stereo camera perception. Whole-body controller trained on 1,000+ hours of human motion data plus simulation across 200,000+ parallel environments.', 'ce6cdf95-329c-450b-ab2c-fab3cb5eb52b', '35b986bf-1223-4bde-92ed-7ba4bcbfd385', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('10ed75d6-9527-40d8-8fd0-788d205f326d', 'CnEVPost / TNW / Interesting Engineering', 'https://cnevpost.com/2026/05/12/unitree-unveils-manned-mecha-gd01/', 'Unitree unveils GD01: world''s first mass-produced manned mecha robot at ¥3.9M ($650K), 2.8m tall transformable', 'Unitree unveiled GD01 on May 12, 2026 — a 2.8-metre transformable mecha with human pilot cockpit. Walks on two legs, folds into quadruped in seconds, weighs ~500 kg with passenger, priced from ¥3.9M (~$650K). World''s first mass-production manned mecha.', 'fa3c7a5b-e830-40bb-9481-2ca6f14fcfe1', '1ef67e56-4d68-4287-bb82-1ac74bbdda14', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('49d7bad4-6a81-431e-bf25-c2897221c37d', 'SCMP / KraneShares / TNW', 'https://www.scmp.com/tech/article/3347611/inside-unitrees-landmark-ipo-what-know-about-chinas-humanoid-giant', 'Unitree IPO targets $7B valuation on Shanghai STAR Market; shipped more humanoids than Tesla in 2025', 'Unitree filed for IPO on Shanghai STAR Market seeking CNY 4.2B ($610M) at ~$7B valuation. Revenue 4.3x to ¥1.7B ($246M) in 2025 with net profit tripling. Shipped more humanoid robots than Tesla in 2025, holds 70% of quadruped market. Would be first pure-play robotics company to IPO.', 'fa3c7a5b-e830-40bb-9481-2ca6f14fcfe1', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('e37f7d85-dfbe-42e5-b41f-8d94f0be2333', 'KraneShares / RoboHorizon', 'https://kraneshares.com/a-complete-guide-to-unitree-robotics-2026-ipo-why-it-matters-for-star-market-etf-kstr-humanoid-robotics-etf-koid/', 'Unitree H1 competes in Beijing E-Town Humanoid Half Marathon alongside 300 robots from 100+ teams', 'Unitree H1 humanoid competed in the April 2026 Beijing E-Town Humanoid Half Marathon event alongside 300 robots from over 100 teams. Demonstrates bipedal locomotion endurance capability in real-world conditions.', 'fa3c7a5b-e830-40bb-9481-2ca6f14fcfe1', '1ef67e56-4d68-4287-bb82-1ac74bbdda14', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('cf349ee5-e15f-4b05-9a1b-5bb1bf6b4c67', 'Robotics 24/7 / Agility Robotics Official', 'https://www.robotics247.com/article/agility_robotics_announces_digit_humanoid_robot_deployment_at_mercado_libre', 'Agility Digit deployed at Mercado Libre San Antonio TX facility for commerce fulfillment', 'Mercado Libre and Agility Robotics signed commercial agreement to integrate Digit humanoid robots into Mercado Libre''s San Antonio, Texas facility for commerce fulfillment. Plans to explore additional use cases across Mercado Libre''s warehouses in Latin America.', '8c2f4fd3-b4b7-42e9-a8f4-1f30353a7831', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('17784421-1e9a-4e6b-a4c0-600122e60019', 'Robot Report / Yahoo Finance', 'https://www.therobotreport.com/toyota-motor-manufacturing-canada-deploys-agility-robotics-digit-humanoids/', 'Agility Digit expands to 10 units at Toyota Canada (TMMC) following successful year-long pilot', 'Toyota Motor Manufacturing Canada (TMMC) expanding from 3 pilot units to 10 commercial Digit robots for RAV4 production logistics (loading/unloading totes from automated tugger). First major automotive OEM RaaS deployment after year-long pilot.', '8c2f4fd3-b4b7-42e9-a8f4-1f30353a7831', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('a6f16b8c-67dc-46df-95f3-0220f4b8de3e', 'CNBC / The Robot Report', 'https://www.cnbc.com/2026/02/11/apptronik-raises-520-million-at-5-billion-valuation-for-apollo-robot.html', 'Apptronik $520M Series A extension at $5B valuation; total funding $935M with Google, John Deere, Qatar co-lead', 'Apptronik raised $520M extension bringing total Series A to $935M at $5B valuation. Co-led by B Capital and Google. New investors include AT&T Ventures, John Deere, Qatar Investment Authority. Plans to expand in Austin, open California office, scale Apollo production.', '110cb526-dd0e-4a32-9270-b21a502ded6e', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('4aacd7c2-c104-44f1-9771-aa0a4a1b073c', 'Automate.org / CNBC', 'https://www.therobotreport.com/apptronik-brings-in-another-520m-to-ramp-up-apollo-production/', 'Apptronik integrates Google DeepMind Gemini Robotics AI models into next-gen Apollo; Jabil manufacturing active', 'Apptronik integrating Google DeepMind''s Gemini Robotics AI foundation models into Apollo. Combined with Jabil manufacturing partnership for scale production. Ongoing pilots at Mercedes-Benz and GXO Logistics. Targets $1B in Apollo orders for 2027 at ~$80K/year per unit.', '110cb526-dd0e-4a32-9270-b21a502ded6e', '35b986bf-1223-4bde-92ed-7ba4bcbfd385', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('fe9caec9-a5f8-48a7-aa49-296a314b4e2d', 'GlobeNewsWire / The Robot Report', 'https://www.globenewswire.com/news-release/2026/04/30/3285118/0/en/1x-opens-neo-factory-in-hayward-ca-america-s-first-vertically-integrated-humanoid-robot-factory-with-consumer-shipments-planned-for-2026.html', '1X NEO Factory commences full-scale production May 1, 2026; 10,000/year capacity sold out in 5 days', '1X NEO Factory (58,000 sq ft, 200+ employees) in Hayward CA commenced full-scale production May 1, 2026. America''s first vertically integrated humanoid robot factory. Initial 10,000 unit/year capacity sold out in 5 days (Oct 28 launch). Scaling to 100,000+/year by end 2027 with new San Carlos factory.', 'fe067c73-5df6-4d5d-a26d-6b99f89886bd', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('37ce112e-3fcd-4ebd-9db0-52c5ece1ec77', '1X Official / Business 2.0', 'https://www.1x.tech/discover/neo-factory', '1X NEO consumer pricing: $20,000 or $499/month subscription; NVIDIA Jetson Thor onboard, US deliveries 2026', 'Each NEO unit features NVIDIA Jetson Thor as core brain (NEO Cortex) for real-time AI inference. In-house manufacturing of motors, batteries, structures, sensors. Consumer price $20,000 or $499/month. US consumer deliveries planned 2026, global expansion 2027.', 'fe067c73-5df6-4d5d-a26d-6b99f89886bd', '1ef67e56-4d68-4287-bb82-1ac74bbdda14', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('f34b7240-3e0c-4da0-a8e1-7bb2fbad5127', 'Interesting Engineering', 'https://interestingengineering.com/ai-robotics/china-agibot-humanoid-robot-calligraphy-dance', 'Agibot A2 humanoid performs live calligraphy and dance at Jakarta cultural event with ASIX partnership', 'On May 21, 2026, Agibot showcased A2 humanoid at Jakarta Indonesia cultural event in partnership with Indonesian AI accelerator ASIX. Robot performed live calligraphy ("Tea for Harmony"), dance, and real-time human interaction hosting duties.', '184de0fc-c3cd-4c43-89a5-102e990d6385', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('40983886-80f6-40d0-8bb9-253d1083b5d2', 'Robotics & Automation News', 'https://roboticsandautomationnews.com/2026/04/21/agibot-unveils-new-generation-of-embodied-ai-robots-and-models-for-real-world-deployment/100781/', 'Agibot unveils new generation embodied AI robots and models for real-world deployment (April 2026)', 'Agibot unveiled next-generation embodied AI robots and foundation models designed for real-world industrial deployment. Launching Genie Sim 3.0 integrated with NVIDIA Isaac Sim. Adopting NVIDIA Isaac GR00T N foundation models for accelerated training.', '184de0fc-c3cd-4c43-89a5-102e990d6385', '35b986bf-1223-4bde-92ed-7ba4bcbfd385', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
INSERT INTO public.ci_monitor_alerts VALUES ('6cf56919-6468-4834-9c05-f98923828f25', 'The Robot Report / Agibot Official', 'https://www.therobotreport.com/agibot-rolls-out-10000th-humanoid-robot/', 'Agibot 10,000th robot rolled out March 2026; 5K→10K in 3 months (4x acceleration), IDC #1 global shipment volume', 'AGIBOT reached 10,000 humanoid robot milestone on March 30, 2026. Scaling from 5,000 to 10,000 in just 3 months (4x production acceleration). IDC ranked AGIBOT first in total humanoid shipment volume globally. Plans to scale to 100 robots at Longcheer by Q3 2026.', '184de0fc-c3cd-4c43-89a5-102e990d6385', 'd446a79e-c53a-4db2-911c-a55a525d7bdc', '2026-05-25 00:16:37.773845', 'pending', NULL, NULL, NULL);
