INSERT INTO public.competitive_alerts VALUES ('f115e451-ae6e-4927-b97c-999adcd65c8d', 'd2fce139-899c-4b81-aeed-29c30ab50fc6', 'score_spike', 'warning', 'Unitree unveils GD01: world''s first mass-produced manned mecha robot at ¥3.9M ($650K), 2.8m tall transformable', 'Unitree unveiled GD01 on May 12, 2026 — a 2.8-metre transformable mecha with human pilot cockpit. Walks on two legs, folds into quadruped in seconds, weighs ~500 kg with passenger, priced from ¥3.9M (~$650K). World''s first mass-production manned mecha.', '{"source": "CnEVPost / TNW / Interesting Engineering", "sourceUrl": "https://cnevpost.com/2026/05/12/unitree-unveils-manned-mecha-gd01/", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.796Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('5374006f-3aac-4851-b3ee-fb07d0278d31', 'd2fce139-899c-4b81-aeed-29c30ab50fc6', 'funding', 'critical', 'Unitree IPO targets $7B valuation on Shanghai STAR Market; shipped more humanoids than Tesla in 2025', 'Unitree filed for IPO on Shanghai STAR Market seeking CNY 4.2B ($610M) at ~$7B valuation. Revenue 4.3x to ¥1.7B ($246M) in 2025 with net profit tripling. Shipped more humanoid robots than Tesla in 2025, holds 70% of quadruped market. Would be first pure-play robotics company to IPO.', '{"source": "SCMP / KraneShares / TNW", "sourceUrl": "https://www.scmp.com/tech/article/3347611/inside-unitrees-landmark-ipo-what-know-about-chinas-humanoid-giant", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.797Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('d26f7587-180b-4fa8-a423-dc1e3c6ecd0e', '9ec06859-c4c9-4049-8186-71bc44a00ce9', 'partnership', 'warning', 'Agility Digit deployed at Mercado Libre San Antonio TX facility for commerce fulfillment', 'Mercado Libre and Agility Robotics signed commercial agreement to integrate Digit humanoid robots into Mercado Libre''s San Antonio, Texas facility for commerce fulfillment. Plans to explore additional use cases across Mercado Libre''s warehouses in Latin America.', '{"source": "Robotics 24/7 / Agility Robotics Official", "sourceUrl": "https://www.robotics247.com/article/agility_robotics_announces_digit_humanoid_robot_deployment_at_mercado_libre", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.798Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('a85e4d19-ae27-4f61-87a7-562e6860197e', '9ec06859-c4c9-4049-8186-71bc44a00ce9', 'partnership', 'warning', 'Agility Digit expands to 10 units at Toyota Canada (TMMC) following successful year-long pilot', 'Toyota Motor Manufacturing Canada (TMMC) expanding from 3 pilot units to 10 commercial Digit robots for RAV4 production logistics (loading/unloading totes from automated tugger). First major automotive OEM RaaS deployment after year-long pilot.', '{"source": "Robot Report / Yahoo Finance", "sourceUrl": "https://www.therobotreport.com/toyota-motor-manufacturing-canada-deploys-agility-robotics-digit-humanoids/", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.798Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('fc933bf7-d28f-43c0-b695-a824fba41e7a', '99311af9-3791-443d-af42-7014001de665', 'funding', 'critical', 'Apptronik $520M Series A extension at $5B valuation; total funding $935M with Google, John Deere, Qatar co-lead', 'Apptronik raised $520M extension bringing total Series A to $935M at $5B valuation. Co-led by B Capital and Google. New investors include AT&T Ventures, John Deere, Qatar Investment Authority. Plans to expand in Austin, open California office, scale Apollo production.', '{"source": "CNBC / The Robot Report", "sourceUrl": "https://www.cnbc.com/2026/02/11/apptronik-raises-520-million-at-5-billion-valuation-for-apollo-robot.html", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.799Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('426478c4-bc43-4675-b89f-568986f7b879', '99311af9-3791-443d-af42-7014001de665', 'partnership', 'warning', 'Apptronik integrates Google DeepMind Gemini Robotics AI models into next-gen Apollo; Jabil manufacturing active', 'Apptronik integrating Google DeepMind''s Gemini Robotics AI foundation models into Apollo. Combined with Jabil manufacturing partnership for scale production. Ongoing pilots at Mercedes-Benz and GXO Logistics. Targets $1B in Apollo orders for 2027 at ~$80K/year per unit.', '{"source": "Automate.org / CNBC", "sourceUrl": "https://www.therobotreport.com/apptronik-brings-in-another-520m-to-ramp-up-apollo-production/", "confidence": "B", "collectedAt": "2026-05-25T00:16:37.800Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('b3cc8223-7408-4a16-971a-08eab2351524', '9c44487b-be8e-4f4c-a01d-83341b646806', 'mass_production', 'critical', '1X NEO Factory commences full-scale production May 1, 2026; 10,000/year capacity sold out in 5 days', '1X NEO Factory (58,000 sq ft, 200+ employees) in Hayward CA commenced full-scale production May 1, 2026. America''s first vertically integrated humanoid robot factory. Initial 10,000 unit/year capacity sold out in 5 days (Oct 28 launch). Scaling to 100,000+/year by end 2027 with new San Carlos factory.', '{"source": "GlobeNewsWire / The Robot Report", "sourceUrl": "https://www.globenewswire.com/news-release/2026/04/30/3285118/0/en/1x-opens-neo-factory-in-hayward-ca-america-s-first-vertically-integrated-humanoid-robot-factory-with-consumer-shipments-planned-for-2026.html", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.801Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('e5f48cb5-2f4a-4c3c-92a4-29775d2cfd6c', '9c44487b-be8e-4f4c-a01d-83341b646806', 'score_spike', 'warning', '1X NEO consumer pricing: $20,000 or $499/month subscription; NVIDIA Jetson Thor onboard, US deliveries 2026', 'Each NEO unit features NVIDIA Jetson Thor as core brain (NEO Cortex) for real-time AI inference. In-house manufacturing of motors, batteries, structures, sensors. Consumer price $20,000 or $499/month. US consumer deliveries planned 2026, global expansion 2027.', '{"source": "1X Official / Business 2.0", "sourceUrl": "https://www.1x.tech/discover/neo-factory", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.802Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('b0d75ac6-b915-4a26-9954-2a7a37c26156', '493b699b-5008-4e04-99ec-a4f18bb91a5f', 'score_spike', 'warning', 'Agibot unveils new generation embodied AI robots and models for real-world deployment (April 2026)', 'Agibot unveiled next-generation embodied AI robots and foundation models designed for real-world industrial deployment. Launching Genie Sim 3.0 integrated with NVIDIA Isaac Sim. Adopting NVIDIA Isaac GR00T N foundation models for accelerated training.', '{"source": "Robotics & Automation News", "sourceUrl": "https://roboticsandautomationnews.com/2026/04/21/agibot-unveils-new-generation-of-embodied-ai-robots-and-models-for-real-world-deployment/100781/", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.802Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
INSERT INTO public.competitive_alerts VALUES ('d65fb89b-421d-47b6-9a58-6cb5e3dc9801', '493b699b-5008-4e04-99ec-a4f18bb91a5f', 'mass_production', 'critical', 'Agibot 10,000th robot rolled out March 2026; 5K→10K in 3 months (4x acceleration), IDC #1 global shipment volume', 'AGIBOT reached 10,000 humanoid robot milestone on March 30, 2026. Scaling from 5,000 to 10,000 in just 3 months (4x production acceleration). IDC ranked AGIBOT first in total humanoid shipment volume globally. Plans to scale to 100 robots at Longcheer by Q3 2026.', '{"source": "The Robot Report / Agibot Official", "sourceUrl": "https://www.therobotreport.com/agibot-rolls-out-10000th-humanoid-robot/", "confidence": "A", "collectedAt": "2026-05-25T00:16:37.803Z"}', false, NULL, NULL, '2026-05-25 00:16:37.773845');
